program_code:
// POU HRL_SkillSet body
IF GVL_Sim.bSimMode THEN
    GVL.diNotAus_Kanal_A                  := GVL_Sim.diNotAus_Kanal_A;
    GVL.diNotAus_Kanal_B                  := GVL_Sim.diNotAus_Kanal_B;
    GVL_HRL.HRL_Enc_horizontal_I1          := GVL_HRL_Sim.HRL_Enc_horizontal_I1;
    GVL_HRL.HRL_Enc_horizontal_I2          := GVL_HRL_Sim.HRL_Enc_horizontal_I2;
    GVL_HRL.HRL_Enc_vertikal_I1            := GVL_HRL_Sim.HRL_Enc_vertikal_I1;
    GVL_HRL.HRL_Enc_vertikal_I2            := GVL_HRL_Sim.HRL_Enc_vertikal_I2;

    GVL_HRL.HRL_Ref_Taster_horizontal      := GVL_HRL_Sim.HRL_Ref_Taster_horizontal;
    GVL_HRL.HRL_LS_innen                   := GVL_HRL_Sim.HRL_LS_innen;
    GVL_HRL.HRL_LS_aussen                  := GVL_HRL_Sim.HRL_LS_aussen;
    GVL_HRL.HRL_Ref_Taster_vertikal        := GVL_HRL_Sim.HRL_Ref_Taster_vertikal;
    GVL_HRL.HRL_Spursensor_1_unten         := GVL_HRL_Sim.HRL_Spursensor_1_unten;
    GVL_HRL.HRL_Spursensor_2_oben          := GVL_HRL_Sim.HRL_Spursensor_2_oben;
    GVL_HRL.HRL_Ref_Taster_Ausleger_vorne  := GVL_HRL_Sim.HRL_Ref_Taster_Ausleger_vorne;
    GVL_HRL.HRL_Ref_Taster_Ausleger_hinten := GVL_HRL_Sim.HRL_Ref_Taster_Ausleger_hinten;
END_IF

HRL_OperatingModes(
    Start := StartButton,
    Stop := NOT (((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B))),
    Reset := ResetButton,
    Schalter := ConfirmationButton,
    Schrittkette_GS := ((HRL_RGB_InitialStateDrive.ResetMethodCall_SRM) AND (HRL_RGB_InitialStateDrive.ResetMethodCall_RGB_Horizontal) AND (HRL_RGB_InitialStateDrive.ResetMethodCall_RGB_Vertical)),
    Count1 := HRL_RGB_InitialStateDrive.Count_SRM_MotorBackw,
    Count2 := HRL_RGB_InitialStateDrive.Count_SRM_MotorForw,
    Alt_abort := OPCUA.Alt_abort,
    Err_detected := HRL_DiagnosisHandler.Err_detected,
    Diag_finished := HRL_DiagnosisHandler.Diag_finished,
    Alt_found := HRL_DiagnosisHandler.Alt_found,
    Cycle_finished := OPCUA.Cycle_finished
);


HRL_NMethod_Auslagern(
    ESS_OK := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    AutomaticMode := HRL_OperatingModes.F1,

    HRL_Enc_horizontal_I1 := GVL_HRL.HRL_Enc_horizontal_I1,
    HRL_Enc_horizontal_I2 := GVL_HRL.HRL_Enc_horizontal_I2,
    HRL_Enc_vertikal_I1 := GVL_HRL.HRL_Enc_vertikal_I1,
    HRL_Enc_vertikal_I2 := GVL_HRL.HRL_Enc_vertikal_I2,

    HRL_Ref_Taster_horizontal := GVL_HRL.HRL_Ref_Taster_horizontal,
    HRL_Ref_Taster_vertikal := GVL_HRL.HRL_Ref_Taster_vertikal,
    HRL_Ref_Taster_Ausleger_vorne := GVL_HRL.HRL_Ref_Taster_Ausleger_vorne,
    HRL_Ref_Taster_Ausleger_hinten := GVL_HRL.HRL_Ref_Taster_Ausleger_hinten,

    HRL_LS_innen := GVL_HRL.HRL_LS_innen,
    HRL_LS_aussen := GVL_HRL.HRL_LS_aussen
);

HRL_DiagnosisHandler(
    Diagnose_gefordert := HRL_OperatingModes.D2,
    ErrorDetectedRaw := HRL_NMethod_Auslagern.Error,
    Reset := ResetButton
);

HRL_RGB_InitialStateDrive(
    MethodCall_InitDrive := HRL_OperatingModes.MethodCall_InitStateDrive,
    ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    InputInitDriveMode := HRL_OperatingModes.InputVar_InitStateDrive,
    TouchSensor01_SRM := GVL_HRL.HRL_Ref_Taster_Ausleger_hinten,
    TouchSensor02_RGB_vertical := GVL_HRL.HRL_Ref_Taster_vertikal,
    TouchSensor03_RGB_horizontal := GVL_HRL.HRL_Ref_Taster_horizontal,
    TOF_Time_TSR := TIME_TSR,
    InitDriveMode := HRL_OperatingModes.A6
);
Init_SRM_MotorBackwards := HRL_RGB_InitialStateDrive.SRM_MotorBackwards;
HRL_Skill_CB_MoveForwards(
    ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    LightBarrierSensor_01 := GVL_HRL.HRL_LS_innen,
    LightBarrierSensor_02 := GVL_HRL.HRL_LS_aussen,
    AutomaticMode := HRL_OperatingModes.F1
);
HRL_CB_forwards := HRL_Skill_CB_MoveForwards.DO_MovingConveyorBelt;
HRL_Skill_CB_MoveBackwards(
    ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    LightBarrierSensor_01 := GVL_HRL.HRL_LS_aussen,
    LightBarrierSensor_02 := GVL_HRL.HRL_LS_innen,
    AutomaticMode := HRL_OperatingModes.F1
);
HRL_CB_backwards := HRL_Skill_CB_MoveBackwards.DO_MovingConveyorBelt;
HRL_Skill_RGB_MoveForwards(
    ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    TouchSensor01 := GVL_HRL.HRL_Ref_Taster_Ausleger_hinten,
    TouchSensor02 := GVL_HRL.HRL_Ref_Taster_Ausleger_vorne,
    TOF_Time_TSR := TIME_TSR,
    AutomaticMode := HRL_OperatingModes.F1
);
HRL_RGB_Forwards01 := HRL_Skill_RGB_MoveForwards.DO_MovingHorizontalRGB_01;
HRL_Skill_RGB_MoveBackwards(
    ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    TouchSensor01 := GVL_HRL.HRL_Ref_Taster_Ausleger_vorne,
    TouchSensor02 := GVL_HRL.HRL_Ref_Taster_Ausleger_hinten,
    TOF_Time_TSR := TIME_TSR,
    AutomaticMode := HRL_OperatingModes.F1
);
HRL_RGB_Backwards01 := HRL_Skill_RGB_MoveBackwards.DO_MovingHorizontalRGB_01;
HRL_Skill_RGB_MoveVerticalForwards(
    ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    TouchSensor01 := GVL_HRL.HRL_Ref_Taster_vertikal,
    EncoderStartPosition01 := GVL_HRL.HRL_Enc_vertikal_I1,
    EncoderStartPosition02 := GVL_HRL.HRL_Enc_vertikal_I2,
    TOF_TSR_TIME := TIME_TSR,
    AutomaticMode := HRL_OperatingModes.F1
);
HRL_RGB_VertikalDown01 := HRL_Skill_RGB_MoveVerticalForwards.DO_MovingVerticalRGB_01;
HRL_Skill_RGB_MoveVerticalBackwards(
    ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    TouchSensor01 := GVL_HRL.HRL_Ref_Taster_vertikal,
    EncoderStartPosition01 := GVL_HRL.HRL_Enc_vertikal_I1,
    EncoderStartPosition02 := GVL_HRL.HRL_Enc_vertikal_I2,
    TOF_TSR_TIME := TIME_TSR,
    AutomaticMode := HRL_OperatingModes.F1
);
HRL_RGB_VertikalUp02 := HRL_Skill_RGB_MoveVerticalBackwards.DO_MovingVerticalRGB_01;
HRL_Skill_RGB_MoveHorizontalForwards(
    ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    TouchSensor01 := GVL_HRL.HRL_Ref_Taster_horizontal,
    EncoderStartPosition01 := GVL_HRL.HRL_Enc_horizontal_I1,
    EncoderStartPosition02 := GVL_HRL.HRL_Enc_horizontal_I2,
    TOF_Time_TSR := TIME_TSR,
    AutomaticMode := HRL_OperatingModes.F1
);
HRL_RGB_HorizontalForwards01 := HRL_Skill_RGB_MoveHorizontalForwards.DO_MovingHorizontalRGB_01;
HRL_Skill_RGB_MoveHorizontalBackwards(
    ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    TouchSensor01 := GVL_HRL.HRL_Ref_Taster_horizontal,
    EncoderStartPosition01 := GVL_HRL.HRL_Enc_horizontal_I1,
    EncoderStartPosition02 := GVL_HRL.HRL_Enc_horizontal_I2,
    TOF_Time_TSR := TIME_TSR,
    AutomaticMode := HRL_OperatingModes.F1
);
HRL_RGB_HorizontalBackwards02 := HRL_Skill_RGB_MoveHorizontalBackwards.DO_MovingHorizontalRGB_01;

bAuslagernAktiv := HRL_NMethod_Auslagern.Busy OR (HRL_NMethod_Auslagern.CurrentStep <> 0);;

HRL_ControlOfOutputs(
    F4 := HRL_OperatingModes.F4,
    F1 := HRL_OperatingModes.F1,
    A2 := HRL_OperatingModes.A2,
    A1 := HRL_OperatingModes.A1,
    A6 := HRL_OperatingModes.A6,
    Start := HRL_OperatingModes.Start,

    CB_forwards :=
        (HRL_CB_forwards AND NOT bAuslagernAktiv)
        OR HRL_NMethod_Auslagern.REQ_CB_forwards,

    CB_backwards :=
        (HRL_CB_backwards AND NOT bAuslagernAktiv)
        OR HRL_NMethod_Auslagern.REQ_CB_backwards,

    RGB_Forwards01 :=
        (HRL_RGB_Forwards01 AND NOT bAuslagernAktiv)
        OR HRL_NMethod_Auslagern.REQ_RGB_Forwards,

    RGB_Forwards02 :=
        HRL_RGB_Forwards02 AND NOT bAuslagernAktiv,

    RGB_Backwards01 :=
        (HRL_RGB_Backwards01 AND NOT bAuslagernAktiv)
        OR HRL_NMethod_Auslagern.REQ_RGB_Backwards,

    RGB_Backwards02 :=
        HRL_RGB_Backwards02 AND NOT bAuslagernAktiv,

    RGB_VertikalDown01 :=
        (HRL_RGB_VertikalDown01 AND NOT bAuslagernAktiv)
        OR HRL_NMethod_Auslagern.REQ_RGB_VerticalDown,

    RGB_VertikalDown02 :=
        HRL_RGB_VertikalDown02 AND NOT bAuslagernAktiv,

    RGB_VertikalUp01 :=
        (HRL_RGB_VertikalUp01 AND NOT bAuslagernAktiv)
        OR HRL_NMethod_Auslagern.REQ_RGB_VerticalUp,

    RGB_VertikalUp02 :=
        HRL_RGB_VertikalUp02 AND NOT bAuslagernAktiv,

    RGB_HorizontalForwards01 :=
        (HRL_RGB_HorizontalForwards01 AND NOT bAuslagernAktiv)
        OR HRL_NMethod_Auslagern.REQ_RGB_HorizontalForward,

    RGB_HorizontalForwards02 :=
        HRL_RGB_HorizontalForwards02 AND NOT bAuslagernAktiv,

    RGB_HorizontalBackwards01 :=
        (HRL_RGB_HorizontalBackwards01 AND NOT bAuslagernAktiv)
        OR HRL_NMethod_Auslagern.REQ_RGB_HorizontalBackward,

    RGB_HorizontalBackwards02 :=
        HRL_RGB_HorizontalBackwards02 AND NOT bAuslagernAktiv,

    Init_RGB_Forwards := Init_SRM_MotorForwards,
    Init_RGB_Backwards := Init_SRM_MotorBackwards,
    Init_RGB_VertikalUp := Init_RGB_VerticalUp,
    Init_RGB_VertikalDown := Init_RGB_VerticalDown,
    Init_RGB_HorizontalForwads := Init_RGB_HorizontalForwards,
    Init_RGB_HorizontalBackwards := Init_RGB_HorizontalBackwards
);
IF GVL_Sim.bSimMode THEN


    GVL_HRL_Sim.HRL_MOT_Foerderband_vorwaerts :=
        HRL_ControlOfOutputs.ConveyorBeltForward;

    GVL_HRL_Sim.HRL_MOT_Foerderband_rueckwaerts :=
        HRL_ControlOfOutputs.ConveyorBeltBackward;

    GVL_HRL_Sim.HRL_MOT_Ausleger_vorwaerts :=
        HRL_ControlOfOutputs.RGB_Forwards;

    GVL_HRL_Sim.HRL_MOT_Ausleger_rueckwaerts :=
        HRL_ControlOfOutputs.RGB_Backwards;

    GVL_HRL_Sim.HRL_MOT_vertikal_runter :=
        HRL_ControlOfOutputs.RGB_VerticalDown;

    GVL_HRL_Sim.HRL_MOT_vertikal_hoch :=
        HRL_ControlOfOutputs.RGB_VerticalUp;

    GVL_HRL_Sim.HRL_MOT_horizontal_zum_Regal :=
        HRL_ControlOfOutputs.RGB_HorizontalForward;

    GVL_HRL_Sim.HRL_MOT_horizontal_zum_Foerderband :=
        HRL_ControlOfOutputs.RGB_HorizontalBackward;

    GVL_HRL_Sim.HRL_K1_1_Zaehler_Zuruecksetzen :=
        GVL_HRL.HRL_K1_1_Zaehler_Zuruecksetzen;

    GVL_HRL_Sim.HRL_K1_2_Zaehler_Zuruecksetzen :=
        GVL_HRL.HRL_K1_2_Zaehler_Zuruecksetzen;

ELSE


    GVL_HRL.HRL_MOT_Foerderband_vorwaerts :=
        HRL_ControlOfOutputs.ConveyorBeltForward;

    GVL_HRL.HRL_MOT_Foerderband_rueckwaerts :=
        HRL_ControlOfOutputs.ConveyorBeltBackward;

    GVL_HRL.HRL_MOT_Ausleger_vorwaerts :=
        HRL_ControlOfOutputs.RGB_Forwards;

    GVL_HRL.HRL_MOT_Ausleger_rueckwaerts :=
        HRL_ControlOfOutputs.RGB_Backwards;

    GVL_HRL.HRL_MOT_vertikal_runter :=
        HRL_ControlOfOutputs.RGB_VerticalDown;

    GVL_HRL.HRL_MOT_vertikal_hoch :=
        HRL_ControlOfOutputs.RGB_VerticalUp;

    GVL_HRL.HRL_MOT_horizontal_zum_Regal :=
        HRL_ControlOfOutputs.RGB_HorizontalForward;

    GVL_HRL.HRL_MOT_horizontal_zum_Foerderband :=
        HRL_ControlOfOutputs.RGB_HorizontalBackward;

END_IF;


IF HRL_OperatingModes.A1 THEN
    sCurrentGemmaState := 'HRL_OperatingModes.A1';
ELSIF HRL_OperatingModes.A2 THEN
    sCurrentGemmaState := 'HRL_OperatingModes.A2';
ELSIF HRL_OperatingModes.A5 THEN
    sCurrentGemmaState := 'HRL_OperatingModes.A5';
ELSIF HRL_OperatingModes.A6 THEN
    sCurrentGemmaState := 'HRL_OperatingModes.A6';
ELSIF HRL_OperatingModes.F1 THEN
    sCurrentGemmaState := 'HRL_OperatingModes.F1';
ELSIF HRL_OperatingModes.F4 THEN
    sCurrentGemmaState := 'HRL_OperatingModes.F4';
ELSIF HRL_OperatingModes.D1 THEN
    sCurrentGemmaState := 'HRL_OperatingModes.D1';
ELSIF HRL_OperatingModes.D3 THEN
    sCurrentGemmaState := 'HRL_OperatingModes.D3';
END_IF;

IF NOT HRL_OperatingModes.D2 THEN
    sLastNonFailureGemmaState := sCurrentGemmaState;
END_IF;

rtD2(CLK := HRL_OperatingModes.D2);

IF rtD2.Q THEN
    OPCUA.LastGEMMAStateBeforeFailure := sLastNonFailureGemmaState;
END_IF;

// POU MBS_SkillSet body
MBS_OperatingModes(
    Start := StartButton,
    Stop := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    Reset := ResetButton,
    Schalter := ConfirmationButton,
    Schrittkette_GS := (((MBS_MR01_InitialStateDrive.ResetMethodCallInitDriveMR01_Backwards) AND (MBS_MR01_InitialStateDrive.ResetMethodCallInitDriveMR01_Forwards) AND (MBS_VSG_InitialStateDrive.ResetMethodCallInitDriveVSG) AND (MBS_DmPD_InitialStateDrive.ResetMethodCallRotateCCW) AND (MBS_DmPD_InitialStateDrive.ResetMethodCallRotateCW) AND (MBS_MR02_InitialStateDrive.ResetMethodCallCuttingProcess)))
);
MBS_ControlOfOutputs(
    F4 := MBS_OperatingModes.F4,
    F1 := MBS_OperatingModes.F1,
    A2 := MBS_OperatingModes.A2,
    A1 := MBS_OperatingModes.A1,
    A6 := MBS_OperatingModes.A6,
    Start := MBS_OperatingModes.Start,
    CB_Forwards := CB_MoveForwards,
    DmPD_Compressor := DmPD_Compressor_HorizontalMove,
    DmPD_Valve := DmPD_Valve_HorizontalMove,
    DmPD_RotateCW_VSGtoMR02 := DmPD_RotateCWformVSGtoMR02,
    DmPD_RotateCW_VSGtoCB := DmPD_RotateCWromVSGtoCB,
    DmPD_RotateCW_MR02toCB := DmPD_RotateCWfromMR02toCB,
    DmPD_RotateCCW_CBtoMR02 := DmPD_RotateCCWformCBtoMR02,
    DmPD_RotateCCW_CBtoVSG := DmPD_RotateCCWformCBtoVSG,
    DmPD_RotateCCW_MR02toVSG := DmPD_RotateCCWformMR02toVSG,
    MR01_HardeningProcess := MR01_HardeningProcess,
    MR01_HorizontalForwards := MR01_MoveOvenslideIn,
    MR01_HoritzontalBackwards := MR01_MoveOvenslideOut,
    MR01_Compressor := MR01_Compressor_SecuringProcess,
    MR01_Valve := MR01_Valve_OvenDoor,
    MR02_CuttingProcess := MR02_CuttingProcess,
    VSG_HorizontalForwards := VSG_MoveHorizontalForwards,
    VSG_HorizontalBackwards := VSG_MoveHorizontalBackwards,
    VSG_Valve_VerticalDown := VSG_Valve_VerticalMove,
    VSG_Valve_SuctionToDmPD := VSG_Valve_SuctionProcessToDmPD,
    VSG_Valve_SuctionToMR01 := VSG_Valve_SuctionProcessToMR01,
    VSG_Compressor_VerticalDown := VSG_Compressor_VerticalMove,
    VSG_Compressor_SuctionToDmPD := VSG_Compressor_SuctionProcessToDmPD,
    VSG_Compressor_SuctionToMR01 := VSG_Compressor_SuctionProcessToMR01,
    Init_DmPD_RotateCCW := Init_DmPD_RotateCCW,
    Init_DmPD_RotateCW := Init_DmPD_RotateCW,
    Init_MR01_HorizontalForwards := Init_MR01_HorizontalForwards,
    Init_MR01_HorizontalBackwards := Init_MR01_HorizontalBackwards,
    Init_MR02_CuttingProcess := Init_MR02_CuttingProcess,
    Init_VSG_HorizontalForwards := Init_VSG_HorizontalForwards,
    Init_VSG_HorizontalBackwards := Init_VSG_HorizontalBackwards
);
GVL_MBS.MBS_MOT_Foerderband_vorwaerts := MBS_ControlOfOutputs.ConveyorBeltForward;
MBS_MR01_InitialStateDrive(
    MethodCall_InitDrive := MethodCall_InitStateDrive,
    ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    InputInitStateDrive := InputVar_InitStateDrive,
    TouchSensor01 := GVL_MBS.MBS_Ref_Taster_Ofenschieber_innen,
    TouchSensor02 := GVL_MBS.MBS_Ref_Taster_Ofenschieber_aussen,
    InitDriveMode := MBS_OperatingModes.A6
);
Init_MR01_HorizontalForwards := MBS_MR01_InitialStateDrive.MotorControlHorizontalForwards;
MBS_VSG_InitialStateDrive(
    MethodCall_InitDrive := MethodCall_InitStateDrive,
    ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    InputInitStateDrive := InputVar_InitStateDrive,
    TouchSensor01 := GVL_MBS.MBS_Ref_Taster_Sauger_Pos_DK,
    TOF_Time_TSR := TIME_TSR,
    InitDriveMode := MBS_OperatingModes.A6
);
Init_VSG_HorizontalForwards := MBS_VSG_InitialStateDrive.DO_HorizontalMoveInitDriveVSG_01;
MBS_DmPD_InitialStateDrive(
    MethodCall_InitDrive := MethodCall_InitStateDrive,
    ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    InputInitialStateDrive := InputVar_InitStateDrive,
    DI02_CW := GVL_MBS.MBS_Ref_Taster_DK_Pos_Foerderband,
    DI01_CCW := GVL_MBS.MBS_Ref_Taster_DK_Pos_Foerderband,
    DI02_CCW := GVL_MBS.MBS_Ref_Taster_DK_Pos_Sauger,
    InitDriveMode := MBS_OperatingModes.A6
);
Init_DmPD_RotateCW := MBS_DmPD_InitialStateDrive.MotorControl_CW;
MBS_MR02_InitialStateDrive(
    MethodCall_InitDrive := MethodCall_InitStateDrive,
    ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    InputInitialStateDrive := InputVar_InitStateDrive,
    TOF_Time_InitCuttingTime := InitTime_Cutting,
    InitDriveMode := MBS_OperatingModes.A6
);
Init_MR02_CuttingProcess := MBS_MR02_InitialStateDrive.CheckMR02MotorControl;
MBS_Skill_MR01_TransportIn(
    ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    TouchSensor_01 := GVL_MBS.MBS_Ref_Taster_Ofenschieber_aussen,
    TouchSensor_02 := GVL_MBS.MBS_Ref_Taster_Ofenschieber_innen,
    TOF_Time_TSR := TIME_TSR,
    AutomaticMode := MBS_OperatingModes.F1
);
MR01_MoveOvenslideIn := MBS_Skill_MR01_TransportIn.DO_MovingHorizontalMR01_01;
MBS_Skill_MR01_TransportOut(
    ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    TouchSensor_01 := GVL_MBS.MBS_Ref_Taster_Ofenschieber_innen,
    TouchSensor_02 := GVL_MBS.MBS_Ref_Taster_Ofenschieber_aussen,
    TOF_Time_TSR := TIME_TSR,
    AutomaticMode := MBS_OperatingModes.F1
);
MR01_MoveOvenslideOut := MBS_Skill_MR01_TransportOut.DO_MovingHorizontalMR01_01;
MBS_Skill_MR01_SecuringWorkpiece(ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)), TouchSensor_01 := GVL_MBS.MBS_Ref_Taster_Ofenschieber_innen, AutomaticMode := MBS_OperatingModes.F1);
MR01_Compressor_SecuringProcess := MBS_Skill_MR01_SecuringWorkpiece.DO_SecuringProcessCompressorMR01_01;
MBS_Skill_MR01_HardeningProcess(ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)), LightSensor_01 := GVL_MBS.MBS_Ref_Taster_Ofenschieber_innen, AutomaticMode := MBS_OperatingModes.F1);
MR01_HardeningProcess := MBS_Skill_MR01_HardeningProcess.DO_HardeningProcessControlMR01;
MBS_Skill_VSG_VerticalMove(
    ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    TouchSensor_01 := GVL_MBS.MBS_Ref_Taster_Sauger_Pos_DK,
    TON_PowerOnDelay_Compressor := PowerOnDelay_Compressor,
    TON_PowerOnDelay_Valve := PowerOnDelay_Valve_VerticalMove,
    AutomaticMode := MBS_OperatingModes.F1
);
VSG_Compressor_VerticalMove := MBS_Skill_VSG_VerticalMove.DO_ControlCompressorVerticalMoveVSG_01;
MBS_Skill_VGS_PickUpWorkpieceToDmPD(
    ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    TouchSensor_01 := GVL_MBS.MBS_Ref_Taster_Sauger_Pos_Ofen,
    TouchSensor_02 := GVL_MBS.MBS_Ref_Taster_Sauger_Pos_DK,
    TON_PowerOnDelay_Compressor := PowerOnDelay_Compressor,
    TON_PowerOnDelay_Valve := PowerOnDelay_Valve_SuctionProcess,
    AutomaticMode := MBS_OperatingModes.F1
);
VSG_Compressor_SuctionProcessToDmPD := MBS_Skill_VGS_PickUpWorkpieceToDmPD.DO_ControlCompressorSuctionProcessVSG_01;
MBS_Skill_VGS_PickUpWorkpieceToOven(
    ESS := ((GVL.diNotAus_Kanal_A) AND (GVL.diNotAus_Kanal_B)),
    TouchSensor_01 := GVL_MBS.MBS_Ref_Taster_Sauger_Pos_DK,
    TouchSensor_02 := GVL_MBS.MBS_Ref_Taster_Sauger_Pos_Ofen,
    TON_PowerOnDelay_Compressor := PowerOnDelay_Compressor,
    TON_PowerOnDelay_Valve := PowerOnDelay_Valve_SuctionProcess,
    AutomaticMode := MBS_OperatingModes.F1
);
VSG_Compressor_SuctionProcessToMR01 := MBS_Skill_VGS_PickUpWorkpieceToOven.DO_ControlCompressorSuctionProcessVSG_01;
